import com.yottastudios.ns.collabspace.announcement.ro.DeleteAnnouncementRo;
import com.yottastudios.ns.collabspace.announcement.ro.UpdateAnnouncementRo;
import com.yottastudios.ns.collabspace.announcement.service.IAnnouncementService;
import com.yottastudios.ns.collabspace.announcement.vo.CreateAnnouncementVo;
import com.yottastudios.ns.collabspace.announcement.vo.GetListAnnouncementVo;
import com.yottastudios.ns.collabspace.core.support.ResponseData;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.ApiResource;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.GetResource;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.PostResource;
import io.swagger.v3.oas.annotations.Operation;
import io.swagger.v3.oas.annotations.tags.Tag;
import jakarta.validation.Valid;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;

import java.util.List;

@Slf4j
@RestController
@Tag(name = "管理后台-平台公告管理")
@ApiResource(path = "/manageback/announcement")
@RequiredArgsConstructor
public class ManagebackAnnouncementController {

    private final IAnnouncementService announcementService;

    /**
     * 创建平台公告（强制设为平台类型，不绑定空间站）
     */
    @PostResource(path = "/create", requiredPermission = false)
    @Operation(summary = "创建平台公告")
    public ResponseData<CreateAnnouncementVo> createPlatformAnnouncement(@RequestBody @Valid CreateAnnouncementRo ro) {
        ro.setAnnouncementCategory(AnnouncementCategory.PLATFORM.getCode());
        ro.setSpaceId(null);
        return ResponseData.success(announcementService.createAnnouncement(ro));
    }

    /**
     * 平台公告列表：
     * - 指定 status 则按状态过滤
     * - 不传 status 则合并所有状态（发布中、待发布、定时、历史）
     */
    @GetResource(path = "/list", requiredPermission = false)
    @Operation(summary = "平台公告列表")
    public ResponseData<List<GetListAnnouncementVo>> listPlatformAnnouncements(
            @RequestParam(required = false) Integer status) {
        if (status != null) {
            return ResponseData.success(announcementService.getAnnounceList(
                    status, null, AnnouncementCategory.PLATFORM.getCode()));
        }
        // 一次查询所有平台公告（不限状态）
        return ResponseData.success(announcementService.getAllPlatformAnnouncements());
    }

    /**
     * 修改/下线平台公告
     */
    @PostResource(path = "/update", requiredPermission = false)
    @Operation(summary = "修改/下线平台公告")
    public ResponseData<Boolean> updatePlatformAnnouncement(@RequestBody @Valid UpdateAnnouncementRo ro) {
        return ResponseData.success(announcementService.changeAnnouncementStatusByAdmin(ro));
    }

    /**
     * 软删除平台公告
     */
    @PostResource(path = "/delete", requiredPermission = false)
    @Operation(summary = "软删除平台公告")
    public ResponseData<Boolean> deletePlatformAnnouncement(@RequestBody @Valid DeleteAnnouncementRo ro) {
        return ResponseData.success(announcementService.deleteAnnouncementByAdmin(ro.getAnnouncementId()));
    }
}

