 82→    @Override
 83→    @Transactional(rollbackFor = Exception.class)
 84→    public CreateAnnouncementVo createAnnouncement(CreateAnnouncementRo ro) {
 85→        log.info("[lbl][2210-公告][Announcement][CREATE] 开始创建/更新公告, category={}, spaceId={}, title={}", ro.getAnnouncementCategory(), ro.getSpaceId(), ro.getTitle());
 86→
 87→        // 0. 兼容旧前端：不传 announcementCategory 时，根据 spaceId 推断类别
 88→        if (ro.getAnnouncementCategory() == null) {
 89→            ro.setAnnouncementCategory(StringUtils.hasText(ro.getSpaceId())
 90→                    ? AnnouncementCategory.SPACE.getCode()
 91→                    : AnnouncementCategory.PLATFORM.getCode());
 92→        }
 93→
 94→        // 1. 空间站公告需校验管理员权限（主管理员 或 文档管理员）
 95→        checkSpaceAnnouncementPermission(ro.getAnnouncementCategory(), ro.getSpaceId());
 96→
 97→        // 2. 校验基本入参
 98→        if (!StringUtils.hasText(ro.getTitle())) {
 99→            throw new BusinessException("公告标题不能为空");
100→        }
101→        if (!StringUtils.hasText(ro.getContent())) {
102→            throw new BusinessException("公告内容不能为空");
103→        }
104→
105→        LocalDateTime now = LocalDateTime.now();
106→        LocalDateTime publishTime;
107→        if (StringUtils.hasText(ro.getPublishTime())) {
108→            publishTime = LocalDateTime.parse(ro.getPublishTime(), DATE_TIME_FORMATTER);
109→        } else {
110→            // 无发布时间 = 立即发布
111→            publishTime = now;
112→        }
113→
114→        // 判断是否定时：发布时间比当前晚 10 分钟以上才算定时
115→        boolean isTimed = publishTime.isAfter(now.plusMinutes(10));
116→        // 明确传了未来时间（超过1分钟容差）但不足10分钟，拒绝；1分钟内视为"立即发布"兼容时钟偏差
117→        if (!isTimed && StringUtils.hasText(ro.getPublishTime()) && publishTime.isAfter(now.plusMinutes(1))) {
118→            throw new BusinessException("定时发布时间必须晚于当前时间至少 10 分钟");
119→        }
120→
121→        // 校验过期时间
122→        if (StringUtils.hasText(ro.getExpireTime())) {
123→            LocalDateTime expireTime = LocalDateTime.parse(ro.getExpireTime(), DATE_TIME_FORMATTER);
124→            if (!expireTime.isAfter(publishTime)) {
125→                throw new BusinessException("过期时间必须晚于发布时间");
126→            }
127→        }
128→
129→        // 2. 获取当前用户信息
130→        Long userId = SessionContext.getUserId();
131→        UserSimpleInfoVo userInfo = apitableGrpcClientService.getUserById(userId);
132→        String userName = userInfo != null ? userInfo.getNickName() : "";
133→
134→        // 3. 如果是编辑（announcementId != null），将旧公告下线
135→        if (ro.getAnnouncementId() != null) {
136→            AnnouncementEntity old = announcementMapper.selectById(ro.getAnnouncementId());
137→            if (old != null) {
138→                old.setStatus(AnnouncementStatus.OFFLINE.getCode());
139→                old.setOfflineTime(now);
140→                announcementMapper.updateById(old);
141→                pushOfflineNotification(old);
142→                log.info("[lbl][2210-公告][Announcement][UPDATE] 编辑操作将旧公告下线, announcementId={}", old.getId());
143→            }
144→        }
145→
146→        // 4. 检查同类型（spaceId + category）是否有当前生效公告，自动下线
147→        offlineActiveAnnouncementByCategory(ro.getSpaceId(), ro.getAnnouncementCategory(), now);
148→
149→        // 5. 构建新公告实体（始终 INSERT）
150→        AnnouncementEntity entity = new AnnouncementEntity();
151→        entity.setTitle(ro.getTitle());
152→        entity.setContent(ro.getContent());
153→        entity.setIsPopup(ro.getIsPopup() != null ? ro.getIsPopup() : false);
154→        entity.setSpaceId(ro.getSpaceId());
155→        entity.setAnnouncementCategory(ro.getAnnouncementCategory());
156→        entity.setCreatorId(userId);
157→        entity.setCreatorName(userName);
158→        entity.setPublisherId(userId);
159→        entity.setPublisherName(userName);
160→        entity.setPublishTime(publishTime);
161→        if (StringUtils.hasText(ro.getExpireTime())) {
162→            entity.setExpireTime(LocalDateTime.parse(ro.getExpireTime(), DATE_TIME_FORMATTER));
163→        }
164→
165→        String operationMessage;
166→        if (isTimed) {
167→            // 6. 定时发布
168→            entity.setType(AnnouncementType.TIMED.getCode());
169→            entity.setStatus(AnnouncementStatus.TIMED.getCode());
170→            operationMessage = "公告已设置定时发布";
171→        } else {
172→            // 7. 立即发布
173→            entity.setType(AnnouncementType.IMMEDIATE.getCode());
174→            entity.setStatus(AnnouncementStatus.PUBLISHED.getCode());
175→            entity.setPublishTime(now);
176→            operationMessage = "公告已立即发布";
177→        }
178→
179→        // 8. INSERT 新实体
180→        announcementMapper.insert(entity);
181→        log.info("[lbl][2210-公告][Announcement][CREATE] 新公告已创建, announcementId={}, status={}, category={}, spaceId={}", entity.getId(), entity.getStatus(), entity.getAnnouncementCategory(), entity.getSpaceId());
182→
183→        // 9. 定时发布 → 发送延迟 MQ 消息
184→        if (isTimed) {
185→            try {
186→                long delayMillis = Duration.between(LocalDateTime.now(), publishTime).toMillis();
187→                Message mqMessage = new Message(entity.getId().toString().getBytes());
188→                rabbitMqSender.sendDelayedMessage(QueueConfig.ANNOUNCEMENT_EXCHANGE, QueueConfig.ANNOUNCEMENT_KEY, mqMessage, delayMillis);
189→                log.info("[lbl][2210-公告][Announcement][CREATE] 定时发布任务已入队, announcementId={}, delayMs={}", entity.getId(), delayMillis);
190→            } catch (Exception e) {
191→                log.error("[lbl][2210-公告][Announcement][CREATE] 定时发布任务入队失败, announcementId={}, error={}", entity.getId(), e.getMessage(), e);
192→                operationMessage += "（定时任务创建失败，请重试）";
193→            }
194→        } else {
195→            // 立即发布 → 推送 WebSocket 通知
196→            pushAnnouncementNotification(entity);
197→        }
198→
199→        CreateAnnouncementVo result = new CreateAnnouncementVo();
200→        result.setId(entity.getId());
201→        result.setTitle(entity.getTitle());
202→        result.setContent(entity.getContent());
203→        result.setPublishTime(entity.getPublishTime());
204→        result.setMessage(operationMessage);
205→
206→        log.info("[lbl][2210-公告][Announcement][CREATE] 创建/更新完成, announcementId={}, userId={}, message={}", entity.getId(), userId, operationMessage);
207→        return result;
208→    }
