233→    private Boolean doChangeAnnouncementStatus(UpdateAnnouncementRo ro, boolean skipPermissionCheck) {
234→        AnnouncementEntity announcement = announcementMapper.selectById(ro.getAnnouncementId());
235→        if (announcement == null) {
236→            return false;
237→        }
238→        if (!skipPermissionCheck) {
239→            checkPlatformAnnouncementWritePermission(announcement.getAnnouncementCategory());
240→            checkSpaceAnnouncementPermission(announcement.getAnnouncementCategory(), announcement.getSpaceId());
241→        }
242→        if (ro.getStatus() != null) {
243→            announcement.setStatus(ro.getStatus());
244→            // 下线时同步记录下线时间
245→            if (ro.getStatus() == AnnouncementStatus.OFFLINE.getCode()) {
246→                announcement.setOfflineTime(LocalDateTime.now());
247→            }
248→        }
249→        if (ro.getType() != null) {
250→            announcement.setType(ro.getType());
251→        }
252→        boolean result = announcementMapper.updateById(announcement) > 0;
253→        if (result && ro.getStatus() != null && ro.getStatus() == AnnouncementStatus.OFFLINE.getCode()) {
254→            pushOfflineNotification(announcement);
255→        }
256→        log.info("[lbl][2210-公告][Announcement][UPDATE] 修改公告状态, announcementId={}, status={}, type={}, result={}", ro.getAnnouncementId(), ro.getStatus(), ro.getType(), result);
257→        return result;
258→    }
