260→    @Override
261→    public GetListAnnouncementVo getLastAnnouncement() {
262→        GetListAnnouncementVo vo = new GetListAnnouncementVo();
263→        // 向后兼容：只查 PLATFORM 类型公告
264→        AnnouncementEntity announcement = announcementMapper.selectOne(new LambdaQueryWrapper<AnnouncementEntity>()
265→                .eq(AnnouncementEntity::getStatus, AnnouncementStatus.PUBLISHED.getCode())
266→                .eq(AnnouncementEntity::getIsDeleted, false)
267→                .eq(AnnouncementEntity::getAnnouncementCategory, AnnouncementCategory.PLATFORM.getCode())
268→                .orderByDesc(AnnouncementEntity::getCreatedAt)
269→                .last("LIMIT 1"));
270→
271→        if (announcement == null) {
272→            return vo;
273→        }
274→
275→        // 修复原有 bug：正确判断是否已读
276→        AnnouncementReadRecordEntity readRecord = announcementReadRecordManager
277→                .selectByAnnouncementIdAndUserId(announcement.getId(), SessionContext.getUserId());
278→        boolean hasRead = readRecord != null;
279→        if (hasRead) {
280→            return vo;
281→        }
282→
283→        vo.setTitle(announcement.getTitle());
284→        vo.setContent(announcement.getContent());
285→        vo.setPublishTime(announcement.getPublishTime());
286→        vo.setIsPopup(announcement.getIsPopup());
287→        vo.setId(announcement.getId());
288→        // 记录已读
289→        addAnnouncementReadRecord(vo.getId(), announcement.getSpaceId());
