294→    public void addAnnouncementReadRecord(Long announcementId, String spaceId) {
295→        Long currentUserId = SessionContext.getUserId();
296→        // 幂等：已存在则跳过
297→        AnnouncementReadRecordEntity existed =
298→                announcementReadRecordManager.selectByAnnouncementIdAndUserId(announcementId, currentUserId);
299→        if (existed != null) {
300→            return;
301→        }
302→        AnnouncementReadRecordEntity readRecord = new AnnouncementReadRecordEntity();
303→        readRecord.setUserId(currentUserId);
304→        readRecord.setAnnouncementId(announcementId);
305→        readRecord.setSpaceId(spaceId != null ? spaceId : "");
306→        readRecord.setReadTime(LocalDateTime.now());
307→        announcementReadRecordMapper.insert(readRecord);
308→        log.info("[lbl][2210-公告][ReadRecord][CREATE] 记录已读, announcementId={}, userId={}, spaceId={}", announcementId, currentUserId, spaceId);
