423→        LocalDateTime now = LocalDateTime.now();
424→        List<AnnouncementEntity> expiredList = announcementMapper.selectList(new LambdaQueryWrapper<AnnouncementEntity>()
425→                .eq(AnnouncementEntity::getStatus, AnnouncementStatus.PUBLISHED.getCode())
426→                .isNotNull(AnnouncementEntity::getExpireTime)
