443→    @Transactional(rollbackFor = Exception.class)
444→    public void publishTimedAnnouncement(Long announcementId) {
445→        AnnouncementEntity announcement = announcementMapper.selectById(announcementId);
446→        // 公告不存在、已取消或为立即发布类型，跳过处理
447→        if (announcement == null
448→                || announcement.getStatus() == AnnouncementStatus.CANCELLED.getCode()
449→                || announcement.getType() == AnnouncementType.IMMEDIATE.getCode()) {
450→            log.info("[lbl][2210-公告][Consumer] 公告无需发布, announcementId={}, status={}, type={}",
451→                    announcementId,
452→                    announcement != null ? announcement.getStatus() : "null",
453→                    announcement != null ? announcement.getType() : "null");
454→            return;
455→        }
456→
457→        LocalDateTime now = LocalDateTime.now();
458→
459→        // 自动下线同分类下已发布的其他公告
460→        offlineActiveAnnouncementByCategory(announcement.getSpaceId(), announcement.getAnnouncementCategory(), now);
461→
462→        // 更新当前公告状态为已发布
463→        announcement.setStatus(AnnouncementStatus.PUBLISHED.getCode());
464→        announcement.setPublishTime(now);
465→        announcementMapper.updateById(announcement);
466→
467→        // 推送 WebSocket 通知
468→        pushAnnouncementNotification(announcement);
469→
470→        log.info("[lbl][2210-公告][Consumer] 定时公告发布成功, announcementId={}, spaceId={}, category={}",
471→                announcement.getId(), announcement.getSpaceId(), announcement.getAnnouncementCategory());
472→    }
