484→    @Override
485→    public void syncAnnouncement() {
486→        // 轮询接口：从外网同步公告
487→        List<AnnouncementEntity> exactAnnouncementList = collabspaceGrpcClientService.getExactAnnouncement();
488→        List<Long> announcementIdList = exactAnnouncementList.stream().map(AnnouncementEntity::getId).toList();
489→        List<AnnouncementEntity> interAnnouncementList = CollectionUtil.isEmpty(announcementIdList) ? new ArrayList<>()
490→                : announcementMapper.selectBatchIds(announcementIdList);
491→        List<Long> existedAnnouncementIdList = interAnnouncementList.stream().map(AnnouncementEntity::getId).toList();
492→        List<AnnouncementEntity> updateList = interAnnouncementList.stream()
493→                .filter(o -> announcementIdList.contains(o.getId())).toList();
494→        List<AnnouncementEntity> addList = exactAnnouncementList.stream()
495→                .filter(o -> !existedAnnouncementIdList.contains(o.getId())).toList();
496→
497→        for (AnnouncementEntity addAnnouncement : addList) {
498→            announcementMapper.insert(addAnnouncement);
499→        }
500→        for (AnnouncementEntity updateAnnouncement : updateList) {
501→            announcementMapper.updateById(updateAnnouncement);
502→        }
503→    }
