591→    private void pushWsNotification(AnnouncementEntity entity, Map<String, Object> data, String message) {
592→        WebSocketResponseModel wsModel = WebSocketResponseModel.builder()
593→                .type(MessageTypeEnum.ADD_ANNOUNCEMENT.getType())
594→                .message(message).status(200).data(data).build();
595→        String msg = JSONUtil.toJsonStr(wsModel);
596→
597→        if (entity.getAnnouncementCategory() == AnnouncementCategory.SPACE.getCode()
598→                && StringUtils.hasText(entity.getSpaceId())) {
599→            // 空间站公告：只推送给该空间站的成员
600→            Collection<Long> userIds = getSpaceUserIds(entity.getSpaceId());
601→            if (!userIds.isEmpty()) {
602→                webSocketHandler.sendUsersToWebSocketClient(msg, userIds);
603→                log.info("[lbl][2210-公告][Announcement][WS] 定向推送空间站成员, spaceId={}, userCount={}", entity.getSpaceId(), userIds.size());
604→            }
605→        } else {
606→            // 平台公告：全量广播
607→            webSocketHandler.sendAllUserToWebSocketClient(msg);
608→        }
609→    }
