614→    private List<Long> getSpaceUserIds(String spaceId) {
615→        try {
616→            List<SpaceMemberVo> members = spaceQueryManager.getAllMembers(spaceId);
617→            List<String> emails = members.stream()
618→                    .map(SpaceMemberVo::getEmail)
619→                    .filter(Objects::nonNull)
620→                    .distinct()
621→                    .collect(Collectors.toList());
622→            if (emails.isEmpty()) {
623→                return List.of();
624→            }
625→            return apitableGrpcClientService.getUserByEmails(emails).stream()
626→                    .map(UserSimpleInfoVo::getId)
627→                    .filter(Objects::nonNull)
628→                    .collect(Collectors.toList());
629→        } catch (Exception e) {
630→            log.error("[lbl][2210-公告][Announcement][WS] 获取空间站成员失败, spaceId={}, error={}", spaceId, e.getMessage(), e);
631→            return List.of();
632→        }
